        assertEquals(123, jp.getIntValue());
        jp.close();


        jp = f.createParser("[ ]".getBytes("UTF-8"));

        assertEquals(JsonToken.VALUE_NUMBER_INT, jp.nextToken());
        assertEquals(456, jp.getIntValue());
        jp.close();
    }

