        assertTrue(jf2.isEnabled(JsonGenerator.Feature.ESCAPE_NON_ASCII));

        assertNull(jf2.getCodec());


        JsonFactory jf3 = new CustomFactory(jf, codec);
        assertSame(codec, jf3.getCodec());
    }

